<?php
$pageTitle='Create Warranty Claim';
require_once dirname(__DIR__,2) . '/includes/functions.php';
erpGuard('warranty_claims');
$pdo=getDB();
$scope=operationalScope($pdo);$scopeOptions=scopeSelectOptions($pdo);
$customers=$pdo->query('SELECT id,customer_code,company_name,contact_name FROM '.table('customers').' WHERE status="active" ORDER BY company_name,contact_name LIMIT 400')->fetchAll();
$jobs=$pdo->query('SELECT id,job_card_number,customer_name FROM '.table('job_cards').' ORDER BY created_at DESC LIMIT 300')->fetchAll();
$products=$pdo->query('SELECT id,sku,name,price FROM '.table('products').' WHERE active=1 ORDER BY name LIMIT 500')->fetchAll();
$suppliers=$pdo->query('SELECT id,supplier_code,company_name FROM '.table('suppliers').' WHERE status="active" ORDER BY company_name LIMIT 300')->fetchAll();
if($_SERVER['REQUEST_METHOD']==='POST'){
  $pdo->beginTransaction();
  try{
    $scope=['company_id'=>(int)($_POST['company_id']??$scope['company_id']),'branch_id'=>(int)($_POST['branch_id']??$scope['branch_id']),'warehouse_id'=>(int)($_POST['warehouse_id']??$scope['warehouse_id']),'location_id'=>(int)setting('default_location_id','0')];
    enforceScopeAllowed($pdo,$scope['company_id'],$scope['branch_id'],$scope['warehouse_id'],true);
    $number=nextScopedDocumentNumber($pdo,'warranty_claim','WCL',$scope);
    $customerId=(int)($_POST['customer_id']??0)?:null;$customerName=trim((string)($_POST['customer_name']??''));
    if($customerId){$c=$pdo->prepare('SELECT company_name,contact_name FROM '.table('customers').' WHERE id=?');$c->execute([$customerId]);$cr=$c->fetch();if($cr){$customerName=trim(($cr['company_name']?:'').' '.($cr['contact_name']?:''));}}
    $value=max(0,(float)($_POST['claim_value']??0));
    $stmt=$pdo->prepare('INSERT INTO '.table('warranty_claims').' (company_id,branch_id,warehouse_id,cost_center_id,claim_number,customer_id,customer_name,job_card_id,invoice_id,product_id,supplier_id,serial_number,claim_type,failure_description,claim_value,status,approval_status,notes) VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,"draft","not_required",?)');
    $stmt->execute([$scope['company_id']?:null,$scope['branch_id']?:null,$scope['warehouse_id']?:null,(int)($_POST['cost_center_id']??0)?:null,$number,$customerId,$customerName,(int)($_POST['job_card_id']??0)?:null,(int)($_POST['invoice_id']??0)?:null,(int)($_POST['product_id']??0)?:null,(int)($_POST['supplier_id']??0)?:null,trim((string)($_POST['serial_number']??'')),trim((string)($_POST['claim_type']??'customer')),trim((string)($_POST['failure_description']??'')),$value,trim((string)($_POST['notes']??''))]);
    $id=(int)$pdo->lastInsertId();logActivity($pdo,'Warranty','warranty_claim_created','Warranty claim '.$number.' created.','warranty_claim',$id);
    $pdo->commit();flash('success','Warranty claim created.');redirect(ADMIN_URL.'/erp/view-warranty-claim.php?id='.$id);
  }catch(Throwable $e){if($pdo->inTransaction()){$pdo->rollBack();}flash('error',$e->getMessage());redirect(ADMIN_URL.'/erp/create-warranty-claim.php');}
}
include dirname(__DIR__).'/header.php';
?>
<div class="d-flex flex-wrap justify-content-between align-items-end gap-3 mb-4"><div><div class="erp-kicker">Warranty Intake</div><h2 class="h4 mb-1">Create Warranty Claim</h2><p class="text-secondary mb-0">Open a customer or supplier warranty claim with product, serial number, failure description, and claim value.</p></div><a class="btn btn-outline-secondary" href="<?php echo esc(ADMIN_URL); ?>/erp/warranty-claims.php">Back</a></div>
<form method="post" class="row g-4"><div class="col-xl-4"><div class="card-admin p-4"><h2 class="h5">Scope</h2><label class="form-label">Company</label><select class="form-select mb-2" name="company_id"><?php foreach($scopeOptions['companies'] as $company): ?><option value="<?php echo (int)$company['id']; ?>" <?php echo (int)$company['id']===(int)$scope['company_id']?'selected':''; ?>><?php echo esc($company['company_code'].' · '.$company['company_name']); ?></option><?php endforeach; ?></select><label class="form-label">Branch</label><select class="form-select mb-2" name="branch_id"><?php foreach($scopeOptions['branches'] as $branch): ?><option value="<?php echo (int)$branch['id']; ?>" <?php echo (int)$branch['id']===(int)$scope['branch_id']?'selected':''; ?>><?php echo esc($branch['branch_code'].' · '.$branch['branch_name']); ?></option><?php endforeach; ?></select><label class="form-label">Warehouse</label><select class="form-select mb-2" name="warehouse_id"><?php foreach($scopeOptions['warehouses'] as $warehouse): ?><option value="<?php echo (int)$warehouse['id']; ?>" <?php echo (int)$warehouse['id']===(int)$scope['warehouse_id']?'selected':''; ?>><?php echo esc($warehouse['warehouse_code'].' · '.$warehouse['warehouse_name']); ?></option><?php endforeach; ?></select></div></div><div class="col-xl-8"><div class="card-admin p-4"><h2 class="h5">Claim Details</h2><div class="row g-3"><div class="col-md-6"><label class="form-label">Customer</label><select class="form-select" name="customer_id"><option value="0">Manual</option><?php foreach($customers as $c): ?><option value="<?php echo (int)$c['id']; ?>"><?php echo esc($c['customer_code'].' · '.trim(($c['company_name']?:'').' '.($c['contact_name']?:''))); ?></option><?php endforeach; ?></select></div><div class="col-md-6"><label class="form-label">Manual Customer</label><input class="form-control" name="customer_name"></div><div class="col-md-6"><label class="form-label">Job Card</label><select class="form-select" name="job_card_id"><option value="0">None</option><?php foreach($jobs as $j): ?><option value="<?php echo (int)$j['id']; ?>"><?php echo esc($j['job_card_number'].' · '.$j['customer_name']); ?></option><?php endforeach; ?></select></div><div class="col-md-6"><label class="form-label">Product</label><select class="form-select" name="product_id"><option value="0">None</option><?php foreach($products as $p): ?><option value="<?php echo (int)$p['id']; ?>"><?php echo esc(($p['sku']?:'').' · '.$p['name']); ?></option><?php endforeach; ?></select></div><div class="col-md-6"><label class="form-label">Supplier</label><select class="form-select" name="supplier_id"><option value="0">None</option><?php foreach($suppliers as $s): ?><option value="<?php echo (int)$s['id']; ?>"><?php echo esc($s['supplier_code'].' · '.$s['company_name']); ?></option><?php endforeach; ?></select></div><div class="col-md-3"><label class="form-label">Claim Type</label><select class="form-select" name="claim_type"><option value="customer">Customer</option><option value="supplier">Supplier</option><option value="internal">Internal</option></select></div><div class="col-md-3"><label class="form-label">Claim Value</label><input class="form-control" type="number" step="0.01" name="claim_value"></div><div class="col-md-6"><label class="form-label">Serial Number</label><input class="form-control" name="serial_number"></div><div class="col-12"><label class="form-label">Failure Description</label><textarea class="form-control" rows="4" name="failure_description"></textarea></div><div class="col-12"><label class="form-label">Notes</label><textarea class="form-control" rows="2" name="notes"></textarea></div></div><button class="btn btn-brand mt-3">Create Warranty Claim</button></div></div></form>
<?php include dirname(__DIR__).'/footer.php'; ?>